// =============================================
// ResultNode.js
// This is the RIGHT node that shows the AI's response.
// =============================================

import React from "react";
import { Handle, Position } from "@xyflow/react";

function ResultNode({ data }) {
  return (
    <div className="custom-node result-node">
      {/* Label at the top */}
      <div className="node-label">🤖 AI Response</div>

      {/* Display area for the AI's answer */}
      <div className="response-text">
        {data.isLoading ? (
          // Show a pulsing animation while waiting
          <span className="loading-text">Thinking...</span>
        ) : data.response ? (
          // Show the AI's response
          data.response
        ) : (
          // Show placeholder text if no response yet
          <span className="placeholder">
            AI response will appear here after you click "Run Flow"
          </span>
        )}
      </div>

      {/*
        Handle = the connection dot.
        type="target" means the line ends here.
        Position.Left means the dot is on the left side.
      */}
      <Handle type="target" position={Position.Left} />
    </div>
  );
}

export default ResultNode;
